    ifnull(sum(total_cost), 0) as totalCost,
    ifnull(sum(tax_paid), 0) as taxPaid,
    ifnull(sum(invoice_amount), 0) as invoiceAmount
from biz_month_report
where report_month >= #{startMonth}
  and report_month <= #{endMonth}

    and company_id = #{companyId}


    and company_id in

        #{cid}

select count(1)
from biz_tax_risk
where report_month >= #{startMonth}
  and report_month <= #{endMonth}

    and company_id = #{companyId}


    and company_id in

        #{cid}

select count(1)
from biz_invoice
where report_month >= #{startMonth}
  and report_month <= #{endMonth}

    and company_id = #{companyId}


    and company_id in

        #{cid}

select report_month as reportMonth, ifnull(sum(total_income), 0) as totalIncome, ifnull(sum(total_cost), 0) as totalCost, ifnull(sum(total_income), 0) - ifnull(sum(total_cost), 0) as netProfit, ifnull(sum(tax_paid), 0) as taxPaid, ifnull(sum(invoice_amount), 0) as invoiceAmount from biz_month_report where report_month >= #{startMonth} and report_month <= #{endMonth}
and company_id = #{companyId}
and company_id in
#{cid}
group by report_month order by report_month asc
